import { createStore } from 'vuex'
import { getUserInfo } from '@/api/user' 
import { publicRequest } from '@/utils/request'
import router from '@/router'
import { showToast } from '@/components/ToastMessage'
import request from '@/utils/request'
import { auth } from '@/api/auth'
import defaultAvatarImage from '@/assets/images/default-avatar.png'

// Token 相关常量
const TOKEN_CONFIG = {
  // 有效期配置
  NORMAL_EXPIRATION_TIME: 2 * 60 * 60 * 1000,  // 普通登录时token有效期2小时
  REMEMBER_EXPIRATION_TIME: 7 * 24 * 60 * 60 * 1000,  // 记住我时token有效期7天
  REFRESH_INTERVAL: 20 * 60 * 1000,  // 刷新间隔20分钟
  REFRESH_THRESHOLD: 30 * 60 * 1000,  // 刷新阈值30分钟

  // 存储键名配置
  STORAGE_KEYS: {
    ACCESS_TOKEN: 'access_token',
    REFRESH_TOKEN: 'refresh_token',
    EXPIRATION: 'token_expiration',
    REMEMBER_ME: 'remember_me'
  }
}

let refreshInterval = null
let isRefreshingToken = false
let refreshSubscribers = []

// Token 刷新订阅机制
const addRefreshSubscriber = (callback) => {
  refreshSubscribers.push(callback)
}

const onTokenRefreshed = (token) => {
  refreshSubscribers.forEach(callback => callback(token))
  refreshSubscribers = []
}

/**
 * 短信验证码场景
 * @enum {string}
 */
export const SMS_SCENE = {
  REGISTER: 'register',
  LOGIN: 'login',
  RESET_PASSWORD: 'reset_password',
  CHANGE_PHONE: 'change_phone',
  BIND_PHONE: 'bind_phone'
}

/**
 * Vuex Store 配置
 * @type {import('vuex').StoreOptions}
 */
export default createStore({
  state: {
    isAuthenticated: false,
    accessToken: null,
    refreshToken: null,
    tokenExpiration: null,
    avatarUpdateTime: 0,
    userInfo: null
  },

  mutations: {
    SET_AUTH_DATA(state, { tokens, expiration }) {
      if (tokens) {
        state.accessToken = tokens.access
        state.refreshToken = tokens.refresh
        state.tokenExpiration = expiration
        state.isAuthenticated = true

        localStorage.setItem('access_token', tokens.access)
        localStorage.setItem('refresh_token', tokens.refresh)
        localStorage.setItem('token_expiration', expiration.toString())
      }
    },

    CLEAR_AUTH(state) {
      state.isAuthenticated = false
      state.accessToken = null
      state.refreshToken = null
      state.tokenExpiration = null

      localStorage.removeItem('access_token')
      localStorage.removeItem('refresh_token')
      localStorage.removeItem('token_expiration')
    },

    SET_AVATAR_UPDATE_TIME(state, timestamp) {
      state.avatarUpdateTime = timestamp
      if (state.userInfo) {
        state.userInfo = { ...state.userInfo }
      }
    },

    SET_USER_INFO(state, userInfo) {
      state.userInfo = userInfo
      if (state.userInfo?.avatar !== userInfo.avatar) {
        state.avatarUpdateTime = Date.now()
      }
    }
  },

  getters: {
    getUserAvatar: (state) => {
      const avatar = state.userInfo?.avatar
      if (!avatar) {
        return defaultAvatarImage
      }
      if (avatar.startsWith('data:image')) {
        return avatar
      }
      if (avatar.startsWith('http')) {
        return `${avatar}?t=${state.avatarUpdateTime}`
      }
      return `${process.env.VUE_APP_API_URL}${avatar}?t=${state.avatarUpdateTime}`
    }
  },

  actions: {
    // 检查认证状态
    async checkAuth({ dispatch, commit }) {
      try {
        const token = localStorage.getItem('access_token')
        const refreshToken = localStorage.getItem('refresh_token')
        const expiration = localStorage.getItem('token_expiration')

        if (!token || !refreshToken || !expiration) {
          commit('CLEAR_AUTH')
          return false
        }

        const now = Date.now()
        const expirationTime = parseInt(expiration)
        const timeToExpire = expirationTime - now

        if (timeToExpire > TOKEN_CONFIG.REFRESH_THRESHOLD) {
          // 恢复认证状态
          commit('SET_AUTH_DATA', {
            tokens: { access: token, refresh: refreshToken },
            expiration: expirationTime
          })

          return true
        }

        // token 即将过期，尝试刷新
        try {
          const newToken = await dispatch('refreshToken')
          if (newToken) {
            return true
          }
        } catch (error) {
        }

        commit('CLEAR_AUTH')
        return false
      } catch (error) {
        commit('CLEAR_AUTH')
        return false
      }
    },

    // 登录
    async login({ commit }, responseData) {
      try {
        // 验证登录响应数据
        if (!responseData?.data?.data) {
          throw new Error('登录失败：无效的认证信息')
        }

        const { access, refresh } = responseData.data.data

        if (!access || !refresh) {
          throw new Error('登录失败：未获取到有效的认证令牌')
        }

        // 设置认证数据
        commit('SET_AUTH_DATA', {
          tokens: { 
            access,
            refresh
          },
          expiration: new Date().getTime() + TOKEN_CONFIG.NORMAL_EXPIRATION_TIME
        })

        // 立即获取用户信息
        try {
          const userResponse = await auth.getUserInfo()
          if (userResponse.data?.code === 200) {
            const userData = {
              ...userResponse.data.data.basic_info,
              ...userResponse.data.data.user
            }
            commit('SET_USER_INFO', userData)
          }
        } catch (error) {
          console.error('Failed to get user info after login:', error)
        }

        return true
      } catch (error) {
        console.error('Login error:', error)
        commit('CLEAR_AUTH')
        throw new Error(error.message || '登录失败，请重试')
      }
    },

    // 登出
    async logout({ commit }) {
      try {
        await auth.logout()
      } finally {
        commit('CLEAR_AUTH')
        router.push('/login')
      }
    },

    // 刷新 token
    async refreshToken({ commit, state }) {
      try {
        const response = await auth.refreshToken({
          refresh: state.refreshToken
        })

        if (!response?.data?.data?.access) {
          throw new Error('刷新令牌失败')
        }

        commit('SET_AUTH_DATA', {
          tokens: {
            access: response.data.data.access,
            refresh: state.refreshToken
          },
          expiration: new Date().getTime() + TOKEN_CONFIG.NORMAL_EXPIRATION_TIME
        })

        return response.data.data.access
      } catch (error) {
        commit('CLEAR_AUTH')
        throw error
      }
    }
  }
})
